const button=(text:string,run:()=>void)=>{const control=document.createElement("button");control.type="button";control.textContent=text;control.addEventListener("click",run);return control;};
const option=(value:string,label=value)=>new Option(label,value);
const groupEntries=(root:ConditionGroup)=>{const entries:{path:number[];label:string}[]=[];const visit=(group:ConditionGroup,path:number[])=>{entries.push({path,label:`${group.kind==="all"?"All":group.kind==="any"?"Any":"Not"} ${path.length?path.join("."):"root"}`});group.children.forEach((child,index)=>{if(child.kind!=="predicate")visit(child,[...path,index]);});};visit(root,[]);return entries;};
const conditionText=(condition:ComposedCondition):string=>condition.kind==="predicate"?`${condition.propertyId} ${condition.operator}${condition.value===undefined?"":` ${String(condition.value)}`}`:`${condition.kind==="all"?"All":condition.kind==="any"?"Any":"Not"} (${condition.children.map(conditionText).join(condition.kind==="any"?" or ":" and ")})`;
const conditionBranches=(root:ConditionGroup)=>{const branches:{path:number[];condition:ComposedCondition}[]=[];const visit=(group:ConditionGroup,path:number[])=>group.children.forEach((child,index)=>{const childPath=[...path,index];branches.push({path:childPath,condition:child});if(child.kind!=="predicate")visit(child,childPath);});visit(root,[]);return branches;};

